-- Create "grouping_policies" table
CREATE TABLE "grouping_policies" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "dimension_keys" jsonb NOT NULL,
  "severity_key" character varying NOT NULL,
  "source_filter" jsonb NOT NULL,
  "enabled" boolean NOT NULL DEFAULT false,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "grouping_policies_name_key" to table: "grouping_policies"
CREATE UNIQUE INDEX "grouping_policies_name_key" ON "grouping_policies" ("name");
-- Create index "groupingpolicy_enabled_updated_at" to table: "grouping_policies"
CREATE INDEX "groupingpolicy_enabled_updated_at" ON "grouping_policies" ("enabled", "updated_at");
-- Create index "groupingpolicy_source_filter" to table: "grouping_policies"
CREATE INDEX "groupingpolicy_source_filter" ON "grouping_policies" USING GIN ("source_filter");
